def salvar_imagem_temp(img_base64, nome_arquivo):
    caminho = os.path.join(os.getcwd(), nome_arquivo)
    if not os.path.exists(caminho):
        imagem_bytes = base64.b64decode(img_base64)
        imagem_stream = io.BytesIO(imagem_bytes)
        imagem = Image.open(imagem_stream)
        imagem.save(caminho)
    return caminho

bolinha_verde_path = salvar_imagem_temp(bolinha_verde_base64, "bolinha_verde.png")
bolinha_amarela_path = salvar_imagem_temp(bolinha_amarela_base64, "bolinha_amarela.png")
bolinha_vermelha_path = salvar_imagem_temp(bolinha_vermelha_base64, "bolinha_vermelha.png")

# Seleção de arquivos

def selecionar_arquivo_excel():
    return filedialog.askopenfilename(
        title="Selecione o arquivo Excel",
        filetypes=[("Arquivos Excel", "*.xlsx")]
    )

def salvar_arquivo_word():
    return filedialog.asksaveasfilename(
        defaultextension=".docx",
        filetypes=[("Documento Word", "*.docx")],
        title="Salvar relatório como"
    )


def gerar_relatorio(cabecalho, versoes, dados, caminho, logo_path=None):
    doc = Document()
    aviso_paragraph = doc.add_paragraph()
    aviso_run = aviso_paragraph.add_run(
        "Essa é uma documentação interna para conhecimento dos MXMers, e o envio para clientes não deve ser feito sem prévio alinhamento."
    )
    aviso_run.font.color.rgb = RGBColor(255, 0, 0)
    aviso_run.bold = True
    aviso_paragraph.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER
    if logo_path and os.path.exists(logo_path):
        # Adiciona imagem centralizada
        paragraph = doc.add_paragraph()
        run = paragraph.add_run()
        run.add_picture(logo_path, width=Inches(2.0))
        paragraph.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER

        # Adiciona o título centralizado
        titulo = doc.add_heading("🔬 Relatório de Testes Automatizados", 0)
        titulo.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER


        # Espaço após o cabeçalho
        doc.add_paragraph()
    else:
        t = doc.add_heading("🔬 Relatório de Testes Automatizados", 0)
        t.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER


    for k, v in cabecalho.items():
        p = doc.add_paragraph()
        p.add_run(f"{k}: {v}").font.size = Pt(12)

    doc.add_paragraph("📌 Histórico de Versões:", style='Heading 1')

    tbl = doc.add_table(rows=1, cols=4)
    tbl.style = 'Light Shading Accent 1'

    hdr = tbl.rows[0].cells
    hdr_text = ['Versão', 'Data', 'Resultado']

    # Cabeçalhos
    for i, txt in enumerate(hdr_text):
        hdr[i].text = txt

    for v in versoes:
        row = tbl.add_row().cells
        for i, key in enumerate(hdr_text):
            paragraph = row[i].paragraphs[0]
            paragraph.clear()

            valor = str(v.get(key, '')).strip()
            if key == 'Resultado':
                paragraph.alignment = WD_PARAGRAPH_ALIGNMENT.LEFT
                run = paragraph.add_run()

                if valor == "Aprovada":
                    run.add_picture(bolinha_verde_path, width=Inches(0.5))
                elif valor == "Reprovada":
                    run.add_picture(bolinha_vermelha_path, width=Inches(0.5))
                elif valor == "Aprovada com Restrição":
                    run.add_picture(bolinha_amarela_path, width=Inches(0.5))
                else:
                    run.add_text(valor)
            else:
                run = paragraph.add_run(valor)
                run.font.color.rgb = RGBColor(0, 0, 0)
                run.bold = True



    total = len(dados)
    ap = dados['Status'].str.lower().eq('sucesso').sum()
    fa = dados['Status'].str.lower().eq('falhou').sum()
    bo = dados['Status'].str.lower().eq('bloqueado').sum()
    doc.add_paragraph("📊 Resumo Executivo:", style='Heading 1')
    rp = doc.add_paragraph()
    rp.add_run("🔹 Total: ").bold = True; rp.add_run(str(total) + "\n")
    rp.add_run("✅ Aprovados: ").bold = True; rp.add_run(str(ap) + "\n")
    rp.add_run("❌ Falhados: ").bold = True; rp.add_run(str(fa) + "\n")
    rp.add_run("🚫 Bloqueados: ").bold = True; rp.add_run(str(bo) + "\n")


    re = dados['Status-PAT'].str.lower().eq('resolvido').sum()    
    pe = dados['Status-PAT'].str.lower().eq('pendente').sum()
    doc.add_paragraph("📶 Status das correções:", style='Heading 1')
    rp = doc.add_paragraph()
    rp.add_run("✅ Resolvidos: ").bold = True; rp.add_run(str(re) + "\n")
    rp.add_run("⏳ Pendentes: ").bold = True; rp.add_run(str(pe) + "\n")


    falhas = dados[dados['Status'].str.lower()=='falhou']
    if not falhas.empty:
        par = doc.add_paragraph("🔬 Detalhamento das Falhas:", style='Heading 1')
        par.runs[0].font.color.rgb = RGBColor(255, 0, 0) 

        for _, f in falhas.iterrows():
            par = doc.add_paragraph(f"{f['ID']} --> {f['Titulo']}", style='Heading 2')
            par.runs[0].font.color.rgb = RGBColor(255, 0, 0)
            doc.add_paragraph(f"· Descrição: {f['Descricao']}")
            pat = str(f['PAT']).replace('.0','') if pd.notna(f['PAT']) else ''
            doc.add_paragraph(f"· PAT: {pat}")
            doc.add_paragraph(f"· Status-PAT: {f['Status-PAT']}")

    # pendentes = dados[dados['Status'].str.lower()=='pendente']

    # if not pendentes.empty:
    #     par = doc.add_paragraph("🔬 Para a próxima versão:", style='Heading 1')
    #     par.runs[0].font.color.rgb = RGBColor(255, 165, 0)

    #     for _, f in pendentes.iterrows():
    #         par = doc.add_paragraph(f"{f['ID']} --> {f['Titulo']}", style='Heading 2')
    #         par.runs[0].font.color.rgb = RGBColor(255, 165, 0) 
    #         doc.add_paragraph(f"· Descrição: {f['Descricao']}")
    #         pat = str(f['PAT']).replace('.0','') if pd.notna(f['PAT']) else ''
    #         doc.add_paragraph(f"· PAT: {pat}")
    #         doc.add_paragraph(f"· Status-PAT: {f['Status-PAT']}")

    doc.add_paragraph("📋 Detalhamento dos Testes:", style='Heading 1')
    cols = ['ID', 'Titulo', 'Status', 'PAT', 'Descricao', 'Status-PAT']

    # Dicionário dos módulos
    modulos = {
        "MXADMINISTRA": "Administrador",
        "AGENDAREL": "AGENDADOR DE RELATÓRIOS",
        "DRIVE": "MXM-DRIVE",
        "SCOM": "CADASTROS COMUNS",
        "SAP": "Patrimônio",
        "SCB": "Contabilidade",
        "SO": "Orçamento",
        "SOC": "Orçamento de Caixa",
        "SFIN": "Cadastros Financeiros",
        "SCP": "Contas a Pagar",
        "SCR": "Contas a Receber",
        "ST": "Tesouraria",
        "SCE": "Cobrança Escritural",
        "SPE": "Pagamento Escritural",
        "SCCC": "Conciliação de Cartão de Crédito",
        "CRM": "CRM de Cobrança",
        "SGS": "Gestão de Suprimentos",
        "SCO": "Compras",
        "SGCC": "Contrato de Compras",
        "SGP": "Gestão de Processos",
        "SGV": "Gestão de Viagens",
        "SMP": "Manutenção Predial",
        "SCU": "Custos",
        "SGE": "Estoque",
        "SGCVE": "Contrato de Vendas",
        "SF": "Faturamento",
        "SIP": "Vendas",
        "SIMP": "Sistema de Importação",
        "SIPADRAO": "Integração Padrão",
        "SFR": "Frete",
        "PCP": "Planejamento de Controle e Produção",
        "SC": "Comissão",
        "EFD-IMPORTADOR": "EFD Importador",
        "ECD": "Escrituração Contábil Digital",
        "ECF": "Escrituração Contábil Fiscal",
        "EFD": "Escrituração Fiscal Digital",
        "EFDREINF": "Escrituração Fiscal Digital - REINF",
        "ValidaçãoTecnologia": "Validação de Tecnologia",
        "componente": "Teste de componentes",
        "SRVATUINFFIN": "Serviço de atualização de informações financeiras"
    }


    # Garante que não tem valores nulos
    dados['Tags'] = dados['Tags'].fillna('SEM_TAG')
    dados['Status-PAT'] = dados['Status-PAT'].fillna('')


    # Separa múltiplas tags (por ';') em listas e remove espaços extras
    dados['Tags_list'] = dados['Tags'].astype(str).str.split(';')
    dados['Tags_list'] = dados['Tags_list'].apply(lambda lst: [t.strip() for t in lst])

    # Função que pega a primeira tag conhecida da linha
    def encontrar_tag_modulo(tags):
        for tag in tags:
            if tag in modulos:
                return tag
        return 'SEM_MODULO_CONHECIDO'

    # Aplica a função à nova coluna 'Tag_modulo'
    dados['Tag_modulo'] = dados['Tags_list'].apply(encontrar_tag_modulo)

    # Agrupa pelo valor da primeira tag conhecida da linha
    agrupado = dados.groupby('Tag_modulo')



    for tag_modulo, grupo in agrupado:
        nome_modulo = modulos.get(tag_modulo, f"[TAG: {tag_modulo}] Módulo Desconhecido")
        doc.add_paragraph(f"📁 {nome_modulo}", style='Heading 2')

        tbl = doc.add_table(rows=1, cols=len(cols))
        tbl.style = 'Table Grid'

        for i, c in enumerate(cols):
            tbl.rows[0].cells[i].text = c

        for _, linha in grupo.iterrows():
            row = tbl.add_row().cells
            for i, c in enumerate(cols):
                val = linha.get(c, '')
                if pd.isna(val):
                    row[i].text = ''
                else:
                    if c == 'PAT':
                        val = str(val).replace('.0', '')
                    row[i].text = str(val)


    doc.save(caminho)
    messagebox.showinfo("Sucesso", f"Relatório gerado: {caminho}")


def gerar_relatorio_externo(versao, dados, base, logo_path=None):  # CLIENTE
    dados = dados.copy()
    dados = dados.fillna('')
    dados = dados.astype(str)

    # Cria uma nova coluna que considera sucesso real ou por resolução do PAT
    dados['Status'] = dados.apply(
        lambda row: 'Sucesso' if row['Status'].strip().lower() == 'sucesso' or row['Status-PAT'].strip().lower() == 'resolvido' else row['Status'],
        axis=1
    )

    # Filtra somente os que são sucesso ou resolvidos no PAT
    df = dados[
        (dados['Status'].str.lower() == 'sucesso') |
        (dados['Status-PAT'].str.lower() == 'resolvido')
    ]

    if df.empty:
        messagebox.showinfo("Aviso", "Nenhum dado para relatório externo.")
        return

    doc = Document()

    if logo_path and os.path.exists(logo_path):
        paragraph = doc.add_paragraph()
        run = paragraph.add_run()
        run.add_picture(logo_path, width=Inches(2.0))
        paragraph.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER
        doc.add_heading("🧪 Relatório de Testes", 0).alignment = WD_PARAGRAPH_ALIGNMENT.CENTER
        doc.add_paragraph()
    else:
        h = doc.add_heading("🧪 Relatório de Testes", 0)
        h.alignment = WD_PARAGRAPH_ALIGNMENT.CENTER

    rp = doc.add_paragraph()
    rp.add_run("✅ Versão: ").bold = True
    rp.add_run(str(versao) + "\n")
    rp.add_run("📋 Total: ").bold = True
    rp.add_run(str(len(df)) + "\n")

    doc.add_paragraph("🟢 Testes com sucesso:")
    cols = ['ID', 'Titulo', 'Status']

    # Tags e mapeamento para módulos
    dados['Tags'] = dados['Tags'].fillna('SEM_TAG')
    dados['Tags_list'] = dados['Tags'].astype(str).str.split(';')
    dados['Tags_list'] = dados['Tags_list'].apply(lambda lst: [t.strip() for t in lst])

    modulos = {
        "MXADMINISTRA": "Administrador", "AGENDAREL": "AGENDADOR DE RELATÓRIOS", "DRIVE": "MXM-DRIVE",
        "SCOM": "CADASTROS COMUNS", "SAP": "Patrimônio", "SCB": "Contabilidade", "SO": "Orçamento",
        "SOC": "Orçamento de Caixa", "SFIN": "Cadastros Financeiros", "SCP": "Contas a Pagar",
        "SCR": "Contas a Receber", "ST": "Tesouraria", "SCE": "Cobrança Escritural",
        "SPE": "Pagamento Escritural", "SCCC": "Conciliação de Cartão de Crédito", "CRM": "CRM de Cobrança",
        "SGS": "Gestão de Suprimentos", "SCO": "Compras", "SGCC": "Contrato de Compras",
        "SGP": "Gestão de Processos", "SGV": "Gestão de Viagens", "SMP": "Manutenção Predial",
        "SCU": "Custos", "SGE": "Estoque", "SGCVE": "Contrato de Vendas", "SF": "Faturamento",
        "SIP": "Vendas", "SIMP": "Sistema de Importação", "SIPADRAO": "Integração Padrão", "SFR": "Frete",
        "PCP": "Planejamento de Controle e Produção", "SC": "Comissão", "EFD-IMPORTADOR": "EFD Importador",
        "ECD": "Escrituração Contábil Digital", "ECF": "Escrituração Contábil Fiscal",
        "EFD": "Escrituração Fiscal Digital", "EFDREINF": "Escrituração Fiscal Digital - REINF",
        "ValidaçãoTecnologia": "Validação de Tecnologia", "componente": "Teste de componentes",
        "SRVATUINFFIN": "Serviço de atualização de informações financeiras"
    }

    def encontrar_tag_modulo(tags):
        for tag in tags:
            if tag in modulos:
                return tag
        return 'SEM_MODULO_CONHECIDO'

    dados['Tag_modulo'] = dados['Tags_list'].apply(encontrar_tag_modulo)

    # Agrupamento apenas com os dados filtrados
    agrupado = df.groupby('Tag_modulo')

    for tag_modulo, grupo in agrupado:
        nome_modulo = modulos.get(tag_modulo, f"[TAG: {tag_modulo}] Módulo Desconhecido")
        doc.add_paragraph(f"📁 {nome_modulo}", style='Heading 2')

        tbl = doc.add_table(rows=1, cols=len(cols))
        tbl.style = 'Light Shading Accent 1'

        for i, c in enumerate(cols):
            tbl.rows[0].cells[i].text = c

        for _, linha in grupo.iterrows():
            row = tbl.add_row().cells
            for i, c in enumerate(cols):
                val = linha.get(c, '')
                if c == 'Status':
                    if linha['Status'].strip().lower() != 'sucesso' and linha['Status-PAT'].strip().lower() == 'resolvido':
                        val = 'Sucesso'
                row[i].text = str(val) if pd.notna(val) else ''

    out = base.replace('.docx', f"_{versao}_cliente.docx")
    doc.save(out)
    messagebox.showinfo("Sucesso", f"Relatório externo: {out}")



def main():
    root = ttk.Window(themename='flatly')
    root.title("Gerador de Relatório de Testes")

    top = ttk.Frame(root, padding=10)
    top.pack(fill='x')
    hist = ttk.Frame(root, padding=10)
    hist.pack(fill='x')
    btnf = ttk.Frame(root, padding=10)
    btnf.pack()

    labels = ["Projeto", "Data de Liberação", "Responsável", "Versão", "Ambiente"]
    entries = {}
    for i, l in enumerate(labels):
        ttk.Label(top, text=l + ":").grid(row=i, column=0, sticky='w')
        e = ttk.Entry(top, width=50)
        e.grid(row=i, column=1, padx=5, pady=2)
        entries[l] = e

    cols = ["Versão", "Data"]
    for j, c in enumerate(cols):
        ttk.Label(hist, text=c, font=(None, 10, 'bold')).grid(row=0, column=j, padx=5)

    rows = []

    def add_row(init=False):
        if rows and not init:
            v, d, _ = rows[-1]
            if not (v.get().strip() and d.get().strip()):
                messagebox.showwarning("Atenção", "Preencha antes de adicionar.")
                return
        r = len(rows) + 1
        e1 = ttk.Entry(hist, width=12)
        e1.grid(row=r, column=0, padx=5, pady=2)
        e2 = ttk.Entry(hist, width=12)
        e2.grid(row=r, column=1, padx=5, pady=2)
      

        resultado_var = ttk.StringVar()
        frame_resultado = ttk.Frame(hist)
        frame_resultado.grid(row=r, column=3, padx=5, pady=2)

        ttk.Radiobutton(frame_resultado, text="Aprovada ", variable=resultado_var, value="Aprovada").pack(side='left')
        ttk.Radiobutton(frame_resultado, text=" Reprovada ", variable=resultado_var, value="Reprovada").pack(side='left')
        ttk.Radiobutton(frame_resultado, text="Aprovada com Restrição", variable=resultado_var, value="Aprovada com Restrição").pack(side='left')

        rows.append((e1, e2, resultado_var))
        if not init:
            messagebox.showinfo("Versão", "Versão adicionada!")

    add_row(init=True)

    ttk.Button(btnf, text="Adicionar Versão", command=add_row).pack(side='left', padx=5)

    def gen():
        ex = selecionar_arquivo_excel()
        if not ex:
            return
        wd = salvar_arquivo_word()
        if not wd:
            return
        df = pd.read_excel(ex)
        cab = {k: v.get() for k, v in entries.items()}
        vlist = []
        for v, d, o in rows:
            if v.get().strip() and d.get().strip():
                vlist.append({
                    "Versão": v.get().strip(),
                    "Data": d.get().strip(),
                    "Resultado": o.get()
                })
        gerar_relatorio(cab, vlist, df, wd, logo_path=logo_temp_path)
        gerar_relatorio_externo(entries['Versão'].get(), df, wd, logo_path=logo_temp_path)

    ttk.Button(btnf, text="Gerar Relatório", bootstyle='success', command=gen).pack(side='left', padx=5)

    root.mainloop()

if __name__=='__main__':
    main()